    h = len(s); w = len(s[0]) if h else 0
    for i in range(h):
        for j in range(w):
            if s[i][j] == rfts.AGENT:
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    ni, nj = i+dr, j+dc
                    if 0 <= ni < h and 0 <= nj < w and s[ni][nj] == rfts.EMPTY:
                        return True
    return False

