def f443(s, a):
    # Is the AGENT on the same main diagonal as the STAR?
    h = len(s); w = len(s[0]) if h else 0
    agent_pos = star_pos = None
    for i in range(h):
        for j in range(w):
            if s[i][j] == rfts.AGENT:
                agent_pos = (i, j)
            if s[i][j] == rfts.STAR:
                star_pos = (i, j)
    return agent_pos and star_pos and agent_pos[0] - agent_pos[1] == star_pos[0] - star_pos[1]

