def f455(s, a):
    # Is there a vertical path of DRAWN from the AGENT to the STAR?
    h = len(s); w = len(s[0]) if h else 0
    agent = star = None
    for i in range(h):
        for j in range(w):
            if s[i][j] == rfts.AGENT:
                agent = (i, j)
            if s[i][j] == rfts.STAR:
                star = (i, j)
    if agent and star and agent[1] == star[1]:
        rng = range(agent[0], star[0]+1) if agent[0] <= star[0] else range(agent[0], star[0]-1, -1)
        for r in rng:
            if s[r][agent[1]] != rfts.DRAWN and (r, agent[1]) != agent and (r, agent[1]) != star:
                return False
        return True
    return False

